class AuthServicer(AuthServiceServicer):
    def __init__(self):
        self.users = {
            'admin': hashlib.sha256('password123'.encode()).hexdigest(),
            'user1': hashlib.sha256('userpass'.encode()).hexdigest(),
            'testuser': hashlib.sha256('test123'.encode()).hexdigest()
        }
        self.secret_key = 'microservice_secret_key_2024'
        self.user_data = {
            'admin': {'name': 'Admin User', 'role': 'administrator', 'email': 'admin@example.com'},
            'user1': {'name': 'John Doe', 'role': 'user', 'email': 'john@example.com'},
            'testuser': {'name': 'Test User', 'role': 'tester', 'email': 'test@example.com'}
        }

    def Login(self, request, context):
        username = request.username
        password = request.password
        
        hashed_password = hashlib.sha256(password.encode()).hexdigest()
        
        if username in self.users and self.users[username] == hashed_password:
            payload = {
                'username': username,
                'exp': datetime.utcnow() + timedelta(hours=24)
            }
            token = jwt.encode(payload, self.secret_key, algorithm='HS256')
            
            return LoginResponse(
                success=True,
                token=token,
                message='Login successful'
            )
        else:
            return LoginResponse(
                success=False,
                token='',
                message='Invalid username or password'
            )

    def GetData(self, request, context):
        user_id = request.userId
        
        if user_id in self.user_data:
            user_info = self.user_data[user_id]
            data_str = f"Name: {user_info['name']}, Role: {user_info['role']}, Email: {user_info['email']}"
            
            return GetDataResponse(
                success=True,
                data=data_str,
                additionalInfo=f"Data retrieved at {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
            )
        else:
            return GetDataResponse(
                success=False,
                data='',
                additionalInfo='User not found'
            )


